//This script will operate a simple door that will open on touch and close after a set time period

float open_time = 5.0; //time in seconds for the door to remain open 

default
{
     touch_start(integer total_number) //run this when someone touches the door
     {
          llSetTimerEvent(open_time); //set the timer before opening
          llSetRot(llEuler2Rot(<0,0,90>*DEG_TO_RAD)); //rotate the door 90 degrees
     }

     timer() //run this when the set time has elapsed
     {
          llSetRot(llEuler2Rot(<0,0,0>*DEG_TO_RAD)); //rotate door back to closed position 
     }
}

//This script will operate a simple door that will open and close on touch and display its state in local chat.

integer doorState = 0; //0= closed, 1= opened

default
{
     touch_start(integer total_number) //run this when someone touches the door
     {
          if(doorState == 0) //if door is closed, open it
          {
               llSetRot(llEuler2Rot(<0,0,90>*DEG_TO_RAD)); //rotate the door 90 degrees
               doorState = 1; //set state to opened
               llOwnerSay("The door has been opened."); //display message in local chat
          }
          else if(doorState == 1) //if door is opened, close it
          {
               llSetRot(llEuler2Rot(<0,0,0>*DEG_TO_RAD)); //rotate door back to closed position 
               doorState = 0; //set state to closed
               llOwnerSay("The door has been closed."); //display message in local chat
          }
     }
}

