//This script will operate a door that will open and close on touch and remain open as long as it isn't touched. The movement of the door will be smooth and anyone can use it.

float open_time = 10.0; //time in seconds for the door to remain open 
float door_angle = 0.0; //initial angle of the door
float door_open_angle = 90.0; //angle at which the door will open
integer doorState = 0; //0= closed, 1= opened, 2= opening, 3= closing
float door_speed = 5.0; //speed at which the door opens/closes (in degrees per second)

default
{
     state_entry() //run this when the object enters the object's inventory
     {
          llSetStatus(STATUS_PHYSICS, TRUE);//enable physics on the door
          llSetRot(llEuler2Rot(<0,0,door_angle>*DEG_TO_RAD));//rotate door to its initial position 
     }

     touch_start(integer total_number) //run this when someone touches the door
     {
          if(doorState == 0 || doorState == 3) //if door is closed or closing, open it
          {
               doorState = 2; //set state to opening
               llSetTimerEvent(open_time); //set the timer before opening
          }
     }

     timer() //run this when the set time has elapsed
     {
          if(doorState == 2) //if door is opening, keep it open
          {
               doorState = 1; //set state to opened
          }
          else if(doorState == 1) //if door is opened, close it after the set time
          {
               doorState = 3; //set state to closing
               llSetTimerEvent(0.0); //remove any existing timer
               llSetTimerEvent(open_time); //set the timer before closing
          }
     }

     timer() //run this when the set time has elapsed
     {
          if(doorState == 3) //if door is closing, close it
          {
               doorState = 0; //set state to closed
          }
     }

     //run this continuously to update the rotation of the door
     on_rez(integer start_param) 
     {
          llResetScript();
     }

     //run this continuously to update the rotation of the door
     touch_end(integer total_number)
     {
          llResetScript(); 
     }

     //run this continuously to update the rotation of the door
     collision_start(integer total_number)
     {
          llSetKeyframedMotion([llEuler2Rot(<0,0,door_angle>*DEG_TO_RAD), llEuler2Rot(<0,0,door_open_angle>*DEG_TO_RAD)], [door_speed]); //smoothly rotate door to open position
          doorState = 2; //set state to opening
     }

     //run this continuously to update the rotation of the door
     collision_end(integer total_number)
     {
          llSetKeyframedMotion([llEuler2Rot(<0,0,door_open_angle>*DEG_TO_RAD), llEuler2Rot(<0,0,door_angle>*DEG_TO_RAD)], [door_speed]); //smoothly rotate door to closed position
          doorState = 3; //set state to closing
     }

} 

Note: This script uses physics to move the door smoothly. Anyone can use the door and it will open/close based on touch and time respectively.

